import pandas as pd

def create_patient_data():
    data = {
        'Patient ID': [1, 1, 1, 2, 2, 3, 3, 3, 3],
        'Age': [25, 25, 25, 30, 30, 28, 28, 28, 28],
        'Sex': ['Male', 'Male', 'Male', 'Female', 'Female', 'Male', 'Male', 'Male', 'Male'],
        'Procedure': ['Gyp#1', 'Gyp#2', 'Gyp#3', 'Gyp#4', 'Gyp#5', 'Gyp#1', 'Gyp#2', 'Gyp#3', 'Gyp#4'],
        'Rating': [8, 9, 7, 6, 5, 9, 8, 7, 6]
    }
    df = pd.DataFrame(data)
    return df

def transform_data(df):
    transformed_df = df.groupby('Patient ID').apply(lambda x: pd.Series({
        'Age': x['Age'].iloc[0],
        'Sex': x['Sex'].iloc[0],
        'Procedure Count': len(x),
        'Average Rating': x['Rating'].mean()
    })).reset_index()
    return transformed_df

def main():
    df = create_patient_data()
    transformed_df = transform_data(df)
    print(transformed_df)

if __name__ == "__main__":
    main()

