            print(f"ID: {employee.id}, Age: {employee.age}, Sex: {employee.sex}, Occupation: {employee.occupation}, Salary: {employee.salary}")

    def get_average_age(self):
        total_age = sum(employee.age for employee in self.employees)
        return total_age / len(self.employees)

    def get_average_salary(self):
        total_salary = sum(employee.salary for employee in self.employees)
        return total_salary / len(self.employees)

    def get_employees_by_occupation(self, occupation):
        return [employee for employee in self.employees if employee.occupation == occupation]

    def get_employees_by_age_range(self, min_age, max_age):
        return [employee for employee in self.employees if min_age <= employee.age <= max_age]

